logger = logging.getLogger("voice")


def _sanitize_transcript(text: str) -> str:
    """Replace characters that can't be encoded in the console's charset.

    Whisper occasionally hallucinates non-Latin scripts (Georgian, CJK, etc.)
    from ambient noise. These crash on Windows cp1252 stdout. Replace them
    with '?' to ensure output always succeeds.
    """
    return text.encode(sys.stdout.encoding or "utf-8", errors="replace").decode(
        sys.stdout.encoding or "utf-8", errors="replace"
    )


APP_NAME = "claude-skill-voice"
CONFIG_FILENAME = "settings.json"
LOCK_FILENAME = "voice.lock"
CONFIG_KEY_WINDOW_X = "window_x"
CONFIG_KEY_WINDOW_Y = "window_y"

AUDIO_DTYPE = "int16"

EXIT_SUCCESS = 0
EXIT_ERROR = 1

MAX_PATH_DISPLAY_LENGTH = 60
TIMER_UPDATE_MS = 200

COLOR_RECORDING = "#cc0000"
COLOR_RECORDING_ACTIVE = "#990000"
COLOR_PAUSED = "#cc8800"
COLOR_PAUSED_ACTIVE = "#996600"
COLOR_DONE = "#228B22"
COLOR_DONE_ACTIVE = "#1a6b1a"
COLOR_MUTED = "#666666"

FONT_STATUS = ("sans-serif", 16, "bold")
FONT_TIMER = ("monospace", 24)
FONT_DETAIL = ("monospace", 9)
FONT_BUTTON = ("sans-serif", 12)

LEVEL_BAR_WIDTH = 260
LEVEL_BAR_HEIGHT = 8
LEVEL_UPDATE_MS = 50
LEVEL_COLOR = "#888888"
LEVEL_BG_COLOR = "#d0d0d0"

COLOR_TRANSCRIBING = "#4477cc"

CHUNK_PROGRESS_HEIGHT = 6
CHUNK_PROGRESS_QUEUED = "#ddaa44"  # amber — audio queued, not yet transcribed
CHUNK_PROGRESS_DONE = COLOR_TRANSCRIBING  # blue — transcribed
CHUNK_PROGRESS_BG = "#d0d0d0"
TRANSCRIBING_POLL_MS = 200


class RecordingError(Exception):
    """Raised when audio recording fails."""


class RecordingCancelled(Exception):
    """Raised when the user cancels recording."""


class LockAcquireError(Exception):
    """Raised when the lock file cannot be acquired."""


def _config_path() -> str:
    """Return the path to the settings JSON file, platform-appropriate."""
    if sys.platform == "win32":
        base = os.environ.get("APPDATA", os.path.expanduser("~"))
    else:
        base = os.environ.get(
            "XDG_CONFIG_HOME", os.path.join(os.path.expanduser("~"), ".config")
        )
    return os.path.join(base, APP_NAME, CONFIG_FILENAME)


class Config:
    """Persistent settings backed by a JSON file."""

    def __init__(self, path: str | None = None):
        self._path = path or _config_path()
        self._data: dict = {}
        self._load()

    def _load(self) -> None:
        if not os.path.exists(self._path):
            return
        try:
            with open(self._path) as f:
                self._data = json.load(f)
        except (json.JSONDecodeError, OSError):
            self._data = {}

    def save(self) -> None:
        os.makedirs(os.path.dirname(self._path), exist_ok=True)
        tmp = self._path + ".tmp"
        with open(tmp, "w") as f:
            json.dump(self._data, f, indent=2)
        os.replace(tmp, self._path)

    @property
    def window_x(self) -> int | None:
        raw = self._data.get(CONFIG_KEY_WINDOW_X)
        return int(raw) if isinstance(raw, (int, float)) else None

    @window_x.setter
    def window_x(self, value: int) -> None:
        self._data[CONFIG_KEY_WINDOW_X] = value

    @property
    def window_y(self) -> int | None:
        raw = self._data.get(CONFIG_KEY_WINDOW_Y)
        return int(raw) if isinstance(raw, (int, float)) else None

    @window_y.setter
    def window_y(self, value: int) -> None:
        self._data[CONFIG_KEY_WINDOW_Y] = value


def _lock_path() -> str:
    """Return path to the PID lockfile."""
    config_dir = os.path.dirname(_config_path())
    return os.path.join(config_dir, LOCK_FILENAME)


def _is_pid_alive(pid: int) -> bool:
    """Check if a process with the given PID is running."""
    if sys.platform == "win32":
        # os.kill(pid, 0) on Windows sends CTRL_C_EVENT (signal 0) to the
        # console process group, which kills the caller. Use OpenProcess instead.
        import ctypes

        PROCESS_QUERY_LIMITED_INFORMATION = 0x1000
        handle = ctypes.windll.kernel32.OpenProcess(
            PROCESS_QUERY_LIMITED_INFORMATION, False, pid
        )
        if handle:
            ctypes.windll.kernel32.CloseHandle(handle)
            return True
        return False
    try:
        os.kill(pid, 0)  # signal 0: check existence, does not kill
        return True
    except PermissionError:
        return True  # exists but we lack permission to signal it
    except OSError:
        return False


def _read_lock_pid() -> int | None:
    """Read and return the PID from the lockfile, or None if unreadable."""
    path = _lock_path()
    if not os.path.exists(path):
        return None
    try:
        with open(path) as f:
            return int(f.read().strip())
    except (ValueError, OSError):
        return None


def _write_lock_file(path: str, pid: int) -> None:
    """Atomically create lockfile with PID. Raises FileExistsError if exists."""
    fd = None
    try:
        fd = os.open(path, os.O_CREAT | os.O_EXCL | os.O_WRONLY)
        os.write(fd, str(pid).encode())
    finally:
        if fd is not None:
            os.close(fd)


def _acquire_lock() -> None:
    """Acquire the PID lockfile. Raises LockAcquireError if held by another.

    Uses O_CREAT|O_EXCL for atomic file creation to prevent race conditions.
    """
    path = _lock_path()
    my_pid = os.getpid()
    os.makedirs(os.path.dirname(path), exist_ok=True)

    # Fast path: try atomic create
    try:
        _write_lock_file(path, my_pid)
        logger.debug("lock acquired: pid=%d", my_pid)
        return
    except FileExistsError:
        pass

    # Lock file exists — check who owns it
    lock_pid = _read_lock_pid()

    if lock_pid is not None and lock_pid == my_pid:
        logger.debug("lock already owned by us: pid=%d", my_pid)
        return

    if lock_pid is not None and _is_pid_alive(lock_pid):
        logger.debug("lock held by live process: pid=%d", lock_pid)
        raise LockAcquireError(
            "Another voice recording session is already running. "
            "Finish that session before starting a new one."
        )

    # Stale lock (process dead or bad PID) — remove and retry
    logger.debug("removing stale lock: pid=%s", lock_pid)
    try:
        os.remove(path)
    except OSError:
        pass
    try:
        _write_lock_file(path, my_pid)
        logger.debug("lock acquired after stale cleanup: pid=%d", my_pid)
    except FileExistsError:
        raise LockAcquireError(
            "Failed to acquire lock. Another session may have started."
        )


def _release_lock() -> None:
    """Remove the PID lockfile only if we own it."""
    lock_pid = _read_lock_pid()
    if lock_pid is not None and lock_pid != os.getpid():
        logger.warning(
            "lock not owned by us (owner=%d, self=%d), not releasing",
            lock_pid,
            os.getpid(),
        )
        return
    try:
        os.remove(_lock_path())
        logger.debug("lock released")
    except OSError:
        pass


def _home_relative_path(path: str) -> str:
    """Convert an absolute path to ~/relative form."""
    home = os.path.expanduser("~")
    if path == home or path.startswith(home + os.sep):
        return "~" + path[len(home) :]
    return path


def _truncate_path(path: str, *, max_length: int = MAX_PATH_DISPLAY_LENGTH) -> str:
    if len(path) > max_length:
        return "..." + path[-(max_length - 3) :]
    return path


def _get_default_input_device() -> int:
    """Return the sounddevice index of the system default input device."""
    default = sd.default.device[0]
    if default is None or default < 0:
        devices = sd.query_devices()
        for i, dev in enumerate(devices):
            if dev["max_input_channels"] > 0:
                return i
        raise RecordingError("No input devices found.")
    return int(default)


def _get_input_devices() -> list[dict]:
    devices = sd.query_devices()
    result = []
    for i, dev in enumerate(devices):
        if dev["max_input_channels"] > 0:
            result.append({"id": i, "name": dev["name"]})
    return result


def record_with_gui(
    cwd: str,
    *,
    device_id: int | None = None,
    config: Config | None = None,
    chunk_manager: ChunkManager | None = None,
) -> tuple[np.ndarray, tk.Tk]:
    """Show a tkinter popup while recording. Returns (audio_data, root).

    On Done, the root window stays alive (mainloop exits via quit()) so it
    can be reused for the transcription progress display. The caller is
    responsible for eventually calling root.destroy().

    When chunk_manager is provided, audio is transcribed in the background
    during recording. Pause triggers a chunk flush. Silence detection
    triggers automatic flushes. On Done, the window transitions to
    "Transcribing..." mode and closes when the worker finishes.

    On Cancel, the root is destroyed and RecordingCancelled is raised.

    Raises:
        RecordingError: If no audio was captured.
        RecordingCancelled: If the user cancelled recording.
    """
    if config is None:
        config = Config()
    if device_id is None:
        device_id = _get_default_input_device()
        logger.debug("resolved default input device: %d", device_id)

    chunks: list[np.ndarray] = []
    recording = True
    paused = False
    cancelled = False
    start_time = time.time()
    paused_elapsed = 0.0
    pause_start = 0.0

    callback_count = [0]
    current_level = [0.0]  # 0.0–1.0, updated by audio callback
    silence_flush_boundary = [None]  # set by callback, read by level timer

    # Set up chunked transcription if manager provided
    silence_detector: SilenceDetector | None = None
    if chunk_manager is not None:
        chunk_manager.bind_chunks(chunks)
        silence_detector = SilenceDetector()

    def audio_callback(indata, _frames, _time_info, status):
        callback_count[0] += 1
        if status:
            logger.warning("audio_callback status: %s", status)
        if recording and not paused:
            chunks.append(indata.copy())
            peak = int(np.max(np.abs(indata)))
            current_level[0] = min(peak / 32768.0 * 4.0, 1.0)
            if callback_count[0] % 50 == 0:
                logger.debug(
                    "callback=%d, chunks=%d, peak=%d, level=%.4f",
                    callback_count[0],
                    len(chunks),
                    peak,
                    current_level[0],
                )
            # Feed silence detector (non-blocking, pure arithmetic)
            if silence_detector is not None and chunk_manager is not None:
                accumulated_s = (
                    (len(chunks) - chunk_manager.boundary) * len(indata) / SAMPLE_RATE
                )
                boundary = silence_detector.feed(
                    current_level[0], len(chunks) - 1, accumulated_s
                )
                if boundary is not None:
                    silence_flush_boundary[0] = boundary
        else:
            current_level[0] = 0.0

    try:
        stream = sd.InputStream(
            samplerate=SAMPLE_RATE,
            channels=AUDIO_CHANNELS,
            dtype=AUDIO_DTYPE,
            callback=audio_callback,
            device=device_id,
        )
    except Exception as e:
        logger.error("Failed to access microphone: %s", e)
        sys.exit(EXIT_ERROR)

    root = tk.Tk()
    root.title("Claude Voice")
    root.attributes("-topmost", True)
    root.resizable(False, False)

    if config.window_x is not None and config.window_y is not None:
        root.geometry(f"+{config.window_x}+{config.window_y}")

    frame = tk.Frame(root, padx=20, pady=15)
    frame.pack()

    timer_frame = tk.Frame(frame)
    timer_frame.pack(pady=(10, 5))
    timer_frame.grid_columnconfigure(0, minsize=160)

    status_var = tk.StringVar(value="Recording:")
    status_label = tk.Label(
        timer_frame,
        textvariable=status_var,
        font=FONT_STATUS,
        fg=COLOR_RECORDING,
        width=11,
        anchor="w",
    )
    status_label.grid(row=0, column=0, sticky="w", padx=(0, 5))

    elapsed_var = tk.StringVar(value="0:00")
    tk.Label(timer_frame, textvariable=elapsed_var, font=FONT_STATUS).grid(
        row=0, column=1, sticky="e"
    )

    display_cwd = _truncate_path(_home_relative_path(cwd))
    tk.Label(frame, text=display_cwd, font=FONT_DETAIL, fg=COLOR_MUTED).pack()

    device_name = sd.query_devices(device_id)["name"]
    tk.Label(frame, text=f"Mic: {device_name}", font=FONT_DETAIL, fg=COLOR_MUTED).pack(
        pady=(0, 5)
    )

    level_canvas = tk.Canvas(
        frame,
        width=LEVEL_BAR_WIDTH,
        height=LEVEL_BAR_HEIGHT,
        bg=LEVEL_BG_COLOR,
        highlightthickness=0,
    )
    level_canvas.pack(pady=(0, 3))
    level_bar = level_canvas.create_rectangle(
        0, 0, 0, LEVEL_BAR_HEIGHT, fill=LEVEL_COLOR, width=0
    )

    # Chunk transcription progress bar (only visible when chunk_manager active)
    # Two layers: queued (amber) behind done (blue)
    chunk_progress_canvas = tk.Canvas(
        frame,
        width=LEVEL_BAR_WIDTH,
        height=CHUNK_PROGRESS_HEIGHT,
        bg=CHUNK_PROGRESS_BG,
        highlightthickness=0,
    )
    chunk_bar_queued = chunk_progress_canvas.create_rectangle(
        0, 0, 0, CHUNK_PROGRESS_HEIGHT, fill=CHUNK_PROGRESS_QUEUED, width=0
    )
    chunk_bar_done = chunk_progress_canvas.create_rectangle(
        0, 0, 0, CHUNK_PROGRESS_HEIGHT, fill=CHUNK_PROGRESS_DONE, width=0
    )
    if chunk_manager is not None:
        chunk_progress_canvas.pack(pady=(0, 10))

    button_frame = tk.Frame(frame)
    button_frame.pack()

    pending_after_ids: list[str] = []

    def _cancel_pending_afters():
        for after_id in pending_after_ids:
            try:
                root.after_cancel(after_id)
            except Exception:
                pass
        pending_after_ids.clear()

    def _save_window_pos():
        try:
            config.window_x = root.winfo_x()
            config.window_y = root.winfo_y()
            config.save()
        except Exception:
            pass

    def cancel_recording():
        nonlocal recording, cancelled
        recording = False
        cancelled = True
        _cancel_pending_afters()
        _save_window_pos()
        root.destroy()

    def toggle_pause():
        nonlocal paused, pause_start, paused_elapsed
        if paused:
            paused_elapsed += time.time() - pause_start
            paused = False
            status_var.set("Recording:")
            status_label.config(fg=COLOR_RECORDING)
            pause_btn.config(text="Pause")
            if silence_detector is not None:
                silence_detector.reset()
            update_timer()
        else:
            # Flush accumulated audio before pausing
            if chunk_manager is not None:
                prev = chunk_manager.boundary
                flushed = chunk_manager.flush()
                if flushed:
                    logger.info(
                        "pause flush: chunks %d-%d",
                        prev,
                        chunk_manager.boundary,
                    )
                silence_flush_boundary[0] = None
            pause_start = time.time()
            paused = True
            status_var.set("Paused:")
            status_label.config(fg=COLOR_PAUSED)
            pause_btn.config(text="Resume")

    def done_recording():
        nonlocal recording
        recording = False
        _cancel_pending_afters()
        _save_window_pos()

        if chunk_manager is not None:
            # Transition to "Transcribing..." mode in same window
            prev = chunk_manager.boundary
            flushed = chunk_manager.flush()
            if flushed:
                logger.info("done flush: chunks %d-%d", prev, chunk_manager.boundary)
            chunk_manager.finish(timeout=0)  # send sentinel, don't block

            # Gray out buttons
            pause_btn.config(state=tk.DISABLED)
            done_btn.config(state=tk.DISABLED)
            status_var.set("Transcribing:")
            status_label.config(fg=COLOR_TRANSCRIBING)

            # Hide level bar, show chunk progress
            level_canvas.pack_forget()
            current_level[0] = 0.0

            def poll_transcription():
                queued_w = int(chunk_manager.queued_fraction() * LEVEL_BAR_WIDTH)
                done_w = int(chunk_manager.progress_fraction() * LEVEL_BAR_WIDTH)
                chunk_progress_canvas.coords(
                    chunk_bar_queued, 0, 0, queued_w, CHUNK_PROGRESS_HEIGHT
                )
                chunk_progress_canvas.coords(
                    chunk_bar_done, 0, 0, done_w, CHUNK_PROGRESS_HEIGHT
                )
                if chunk_manager.is_done():
                    root.quit()
                else:
                    after_id = root.after(TRANSCRIBING_POLL_MS, poll_transcription)
                    pending_after_ids.append(after_id)

            poll_transcription()
            return  # stay in mainloop

        root.quit()  # exit mainloop but keep window alive for progress

    btn_width = 7

    cancel_btn = tk.Button(
        button_frame,
        text="Cancel",
        font=FONT_BUTTON,
        command=cancel_recording,
        bg=COLOR_RECORDING,
        fg="white",
        activebackground=COLOR_RECORDING_ACTIVE,
        activeforeground="white",
        width=btn_width,
        pady=5,
    )
    cancel_btn.pack(side=tk.LEFT, padx=(0, 5))

    pause_btn = tk.Button(
        button_frame,
        text="Pause",
        font=FONT_BUTTON,
        command=toggle_pause,
        bg=COLOR_PAUSED,
        fg="white",
        activebackground=COLOR_PAUSED_ACTIVE,
        activeforeground="white",
        width=btn_width,
        pady=5,
    )
    pause_btn.pack(side=tk.LEFT, padx=(0, 5))

    done_btn = tk.Button(
        button_frame,
        text="Done",
        font=FONT_BUTTON,
        command=done_recording,
        bg=COLOR_DONE,
        fg="white",
        activebackground=COLOR_DONE_ACTIVE,
        activeforeground="white",
        width=btn_width,
        pady=5,
    )
    done_btn.pack(side=tk.LEFT)

    root.bind("<Escape>", lambda _e: cancel_recording())
    root.bind("<space>", lambda _e: toggle_pause())
    root.bind("<Return>", lambda _e: done_recording())

    def update_timer():
        if recording and not paused:
            elapsed = int(time.time() - start_time - paused_elapsed)
            mins, secs = divmod(elapsed, 60)
            elapsed_var.set(f"{mins}:{secs:02d}")
            after_id = root.after(TIMER_UPDATE_MS, update_timer)
            pending_after_ids.append(after_id)

    def update_level():
        if recording:
            level = current_level[0] if not paused else 0.0
            bar_width = int(level * LEVEL_BAR_WIDTH)
            level_canvas.coords(level_bar, 0, 0, bar_width, LEVEL_BAR_HEIGHT)

            # Check silence-triggered flush (set by audio callback)
            if chunk_manager is not None and silence_flush_boundary[0] is not None:
                boundary = silence_flush_boundary[0]
                silence_flush_boundary[0] = None
                prev = chunk_manager.boundary
                chunk_manager.flush(boundary=boundary)
                logger.info(
                    "silence flush: chunks %d-%d, level=%.4f",
                    prev,
                    boundary,
                    current_level[0],
                )

            # Update chunk progress bar (queued = amber, done = blue)
            if chunk_manager is not None:
                queued_w = int(chunk_manager.queued_fraction() * LEVEL_BAR_WIDTH)
                done_w = int(chunk_manager.progress_fraction() * LEVEL_BAR_WIDTH)
                chunk_progress_canvas.coords(
                    chunk_bar_queued, 0, 0, queued_w, CHUNK_PROGRESS_HEIGHT
                )
                chunk_progress_canvas.coords(
                    chunk_bar_done, 0, 0, done_w, CHUNK_PROGRESS_HEIGHT
                )

            after_id = root.after(LEVEL_UPDATE_MS, update_level)
            pending_after_ids.append(after_id)

    root.protocol("WM_DELETE_WINDOW", cancel_recording)

    try:
        stream.start()
        update_timer()
        update_level()
        root.mainloop()
    finally:
        stream.stop()
        stream.close()

    logger.debug(
        "recording ended: chunks=%d, callback_count=%d, cancelled=%s",
        len(chunks),
        callback_count[0],
        cancelled,
    )

    if cancelled:
        raise RecordingCancelled("Recording cancelled.")

    if not chunks:
        raise RecordingError("No audio captured.")

    audio_data = np.concatenate(chunks, axis=0)
    duration = len(audio_data) / SAMPLE_RATE
    logger.info("Captured %.1fs of audio.", duration)
    return audio_data, root


def main() -> None:
    parser = argparse.ArgumentParser(description="Voice-to-text for Claude Code CLI")
    parser.add_argument(
        "--model",
        type=str,
        default=DEFAULT_MODEL_SIZE,
        choices=["tiny", "base", "small"],
        help="Whisper model size (default: base)",
    )
    parser.add_argument(
        "--device",
        type=int,
        default=None,
        help="Audio input device ID (use --list-devices to see available devices)",
    )
    parser.add_argument(
        "--list-devices",
        action="store_true",
        help="List available audio input devices and exit",
    )
    parser.add_argument(
        "--wav-output",
        type=str,
        default=None,
        metavar="PATH",
        help="Save recorded audio to this WAV file (kept after transcription)",
    )
    parser.add_argument(
        "--wav-input",
        type=str,
        default=None,
        metavar="PATH",
        help="Transcribe from an existing WAV file instead of recording",
    )
    parser.add_argument(
        "--stream",
        action="store_true",
        help="Stream transcript chunks to stdout as they complete",
    )
    parser.add_argument(
        "--debug",
        action="store_true",
        help="Enable debug logging to stderr",
    )
    args = parser.parse_args()

    log_level = logging.DEBUG if args.debug else logging.INFO
    handler = logging.StreamHandler(sys.stderr)
    handler.setFormatter(
        logging.Formatter("%(asctime)s %(levelname)s %(name)s: %(message)s")
    )
    # Configure our loggers only — avoid flooding with third-party debug spam
    for name in ("voice", "whisper", "chunks"):
        mod_logger = logging.getLogger(name)
        mod_logger.addHandler(handler)
        mod_logger.setLevel(log_level)
    logger.addHandler(handler)
    logger.setLevel(log_level)

    if args.list_devices:
        devices = _get_input_devices()
        if not devices:
            logger.error("No input devices found.")
            sys.exit(EXIT_ERROR)
        for dev in devices:
            logger.info("  %d: %s", dev["id"], dev["name"])
        sys.exit(EXIT_SUCCESS)

    # --wav-input: transcribe-only mode (no recording, no lock, no GUI)
    if args.wav_input:
        if not os.path.exists(args.wav_input):
            logger.error("WAV file not found: %s", args.wav_input)
            sys.exit(EXIT_ERROR)
        start_whisper_preload()
        t_start = time.time()
        transcript = transcribe_wav(args.wav_input, model_size=args.model)
        t_elapsed = time.time() - t_start
        try:
            with wave.open(args.wav_input, "rb") as wf:
                audio_duration = wf.getnframes() / wf.getframerate()
        except Exception:
            audio_duration = 0.0
        logger.info(
            "Transcribed %.1fs audio in %.1fs (model=%s)",
            audio_duration,
            t_elapsed,
            args.model,
        )
        print("[BEGIN]")
        print(_sanitize_transcript(transcript))
        print("[END]")
        sys.exit(EXIT_SUCCESS)

    try:
        _acquire_lock()
    except LockAcquireError as e:
        logger.error("%s", e)
        sys.exit(EXIT_ERROR)

    try:
        # Start importing faster-whisper in background while user records
        start_whisper_preload()
        cfg = Config()
        cwd = os.getcwd()

        # Create chunk manager for background transcription during recording
        chunk_mgr = ChunkManager(model_size=args.model)
        begun = [False]  # track whether [BEGIN] has been printed

        if args.stream:

            def _stream_chunk(text: str) -> None:
                if not begun[0]:
                    print("[BEGIN]", flush=True)
                    begun[0] = True
                print(_sanitize_transcript(text), flush=True)

            chunk_mgr.set_stream_callback(_stream_chunk)
        chunk_mgr.start_worker()

        gui_root: tk.Tk | None = None
        try:
            audio_data, gui_root = record_with_gui(
                cwd,
                device_id=args.device,
                config=cfg,
                chunk_manager=chunk_mgr,
            )
        except RecordingCancelled:
            # In stream mode, [BEGIN] + chunks may already be on stdout.
            # [CANCEL] terminates the block (or stands alone if no [BEGIN]).
            print("[CANCEL]")
            sys.exit(EXIT_SUCCESS)
        except RecordingError as e:
            logger.error("%s", e)
            sys.exit(EXIT_ERROR)

        # GUI handled "Transcribing..." phase — root is already quit
        if gui_root is not None:
            try:
                gui_root.destroy()
            except Exception:
                pass

        # Save WAV if requested
        audio_duration = len(audio_data) / SAMPLE_RATE
        if args.wav_output:
            wav_path = os.path.abspath(args.wav_output)
            save_wav_to(audio_data, wav_path)
            logger.info("Saved audio to %s", wav_path)

        transcript = chunk_mgr.get_transcript()

        if not transcript:
            print("[BEGIN]")
            print("[END]")
            logger.warning("No speech detected in audio.")
            sys.exit(EXIT_SUCCESS)

        if args.stream:
            # Chunks already streamed with [BEGIN] prefix
            print("[END]")
        else:
            print("[BEGIN]")
            print(_sanitize_transcript(transcript))
            print("[END]")
    finally:
        _release_lock()


if __name__ == "__main__":
    main()
